use chrono::{DateTime, Utc};
use uuid::Uuid;

use super::todo_title::TodoTitle;
use super::user::UserId;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WaitingForId(Uuid);

impl Default for WaitingForId {
    fn default() -> Self {
        Self::new()
    }
}

impl WaitingForId {
    pub fn new() -> Self {
        Self(Uuid::new_v4())
    }

    pub fn from_uuid(uuid: Uuid) -> Self {
        Self(uuid)
    }

    pub fn as_uuid(&self) -> &Uuid {
        &self.0
    }
}

/// The person or entity the user is waiting on. Non-empty, max 100 chars, trimmed.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WaitingOnPerson(String);

const WAITING_ON_MAX_LENGTH: usize = 100;

#[derive(Debug, Clone, thiserror::Error)]
pub enum WaitingOnPersonError {
    #[error("Waiting-on person cannot be empty")]
    Empty,
    #[error("Waiting-on person too long (max {max}, got {actual})")]
    TooLong { max: usize, actual: usize },
}

impl WaitingOnPerson {
    pub fn parse(input: String) -> Result<Self, WaitingOnPersonError> {
        let trimmed = input.trim().to_string();
        if trimmed.is_empty() {
            return Err(WaitingOnPersonError::Empty);
        }
        if trimmed.len() > WAITING_ON_MAX_LENGTH {
            return Err(WaitingOnPersonError::TooLong {
                max: WAITING_ON_MAX_LENGTH,
                actual: trimmed.len(),
            });
        }
        Ok(Self(trimmed))
    }

    pub fn as_str(&self) -> &str {
        &self.0
    }
}

/// An item the user is waiting on from someone else.
///
/// State machine:
///   Active --complete()--> Completed (received/resolved)
///
/// Completed items are removed from the active Waiting For list.
#[derive(Debug, Clone)]
pub enum WaitingForItem {
    Active {
        id: WaitingForId,
        user_id: UserId,
        title: TodoTitle,
        waiting_on: WaitingOnPerson,
        created_at: DateTime<Utc>,
    },
    Completed {
        id: WaitingForId,
        user_id: UserId,
        title: TodoTitle,
        waiting_on: WaitingOnPerson,
        created_at: DateTime<Utc>,
        completed_at: DateTime<Utc>,
    },
}

impl WaitingForItem {
    pub fn new(user_id: UserId, title: TodoTitle, waiting_on: WaitingOnPerson) -> Self {
        Self::Active {
            id: WaitingForId::new(),
            user_id,
            title,
            waiting_on,
            created_at: Utc::now(),
        }
    }

    pub fn from_parts(
        id: WaitingForId,
        user_id: UserId,
        title: TodoTitle,
        waiting_on: WaitingOnPerson,
        created_at: DateTime<Utc>,
        completed_at: Option<DateTime<Utc>>,
    ) -> Self {
        match completed_at {
            Some(completed_at) => Self::Completed {
                id,
                user_id,
                title,
                waiting_on,
                created_at,
                completed_at,
            },
            None => Self::Active {
                id,
                user_id,
                title,
                waiting_on,
                created_at,
            },
        }
    }

    pub fn id(&self) -> &WaitingForId {
        match self {
            Self::Active { id, .. } | Self::Completed { id, .. } => id,
        }
    }

    pub fn user_id(&self) -> &UserId {
        match self {
            Self::Active { user_id, .. } | Self::Completed { user_id, .. } => user_id,
        }
    }

    pub fn title(&self) -> &TodoTitle {
        match self {
            Self::Active { title, .. } | Self::Completed { title, .. } => title,
        }
    }

    pub fn waiting_on(&self) -> &WaitingOnPerson {
        match self {
            Self::Active { waiting_on, .. } | Self::Completed { waiting_on, .. } => waiting_on,
        }
    }

    pub fn created_at(&self) -> &DateTime<Utc> {
        match self {
            Self::Active { created_at, .. } | Self::Completed { created_at, .. } => created_at,
        }
    }

    pub fn is_active(&self) -> bool {
        matches!(self, Self::Active { .. })
    }

    pub fn is_completed(&self) -> bool {
        matches!(self, Self::Completed { .. })
    }

    /// Transitions an Active waiting-for item to Completed (received/resolved).
    /// If already completed, returns self unchanged.
    pub fn complete(self) -> Self {
        match self {
            Self::Active {
                id,
                user_id,
                title,
                waiting_on,
                created_at,
            } => Self::Completed {
                id,
                user_id,
                title,
                waiting_on,
                created_at,
                completed_at: Utc::now(),
            },
            completed @ Self::Completed { .. } => completed,
        }
    }
}

