  1→/**
  2→ * Projects focus management and empty state
  3→ * -- progressive enhancement for HTMX.
  4→ *
  5→ * Focus management:
  6→ * After an HTMX complete or delete swap removes a project item from the DOM,
  7→ * focus would otherwise be lost (sent to <body>). This script moves focus
  8→ * to the logical next element:
  9→ *   1. Next sibling project-item (if one exists)
 10→ *   2. Previous sibling project-item (if deleted was last in list)
 11→ *   3. The "Add project" input (if the list is now empty)
 12→ *
 13→ * Inline edit focus:
 14→ * Entering edit mode focuses the edit input. Saving or canceling
 15→ * focuses the edit link on the restored item.
 16→ *
 17→ * Empty state transitions:
 18→ * When the last item is removed, shows the empty state message
 19→ * and hides the empty list. When items are added, hides the
 20→ * message and shows the list.
 21→ *
 22→ * A11y: Focus management after DOM removal is required by WCAG 2.4.3
 23→ * (Focus Order) and is part of our HTMX Focus Management Protocol.
 24→ */
 25→(function () {
 26→  "use strict";
 27→
 28→  var pendingFocusTarget = null;
 29→  var pendingDeleteSwap = false;
 30→
 31→  document.body.addEventListener("htmx:beforeSwap", function (e) {
 32→    var target = e.detail.target;
 33→
 34→    if (!target || !target.classList || !target.classList.contains("project-item")) {
 35→      return;
 36→    }
 37→
 38→    var responseText = e.detail.xhr ? e.detail.xhr.responseText : "";
 39→
 40→    // Empty response = complete or delete operation (item removed)
 41→    if (responseText.trim() === "") {
 42→      pendingDeleteSwap = true;
 43→
 44→      var nextItem = target.nextElementSibling;
 45→      var prevItem = target.previousElementSibling;
 46→
 47→      if (nextItem && nextItem.classList.contains("project-item")) {
 48→        pendingFocusTarget = { type: "element", el: nextItem };
 49→      } else if (prevItem && prevItem.classList.contains("project-item")) {
 50→        pendingFocusTarget = { type: "element", el: prevItem };
 51→      } else {
 52→        pendingFocusTarget = { type: "element", el: document.getElementById("project-title") };
 53→      }
 54→      return;
 55→    }
 56→
 57→    // Check if the response contains the edit form (entering edit mode)
 58→    if (responseText.indexOf("project-item__edit-form") !== -1) {
 59→      pendingFocusTarget = { type: "selector", selector: "#" + target.id + " .project-item__edit-input" };
 60→      return;
 61→    }
 62→
