#[derive(Debug, thiserror::Error)]
pub enum CompleteWaitingForError {
    #[error("Waiting-for item not found")]
    NotFound,
    #[error("Not authorized to complete this waiting-for item")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "complete_waiting_for_item",
    skip(pool),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn complete_waiting_for_item(
    pool: &PgPool,
    item_id: &WaitingForId,
    user_id: &UserId,
) -> Result<(), CompleteWaitingForError> {
    let item = waiting_for_repository::find_waiting_for_item_by_id(pool, item_id)
        .await
        .map_err(|e| CompleteWaitingForError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(CompleteWaitingForError::NotFound)?;

    if item.user_id() != user_id {
        return Err(CompleteWaitingForError::Unauthorized);
    }

    let completed = item.complete();
    if let WaitingForItem::Completed { completed_at, .. } = &completed {
        waiting_for_repository::complete_waiting_for_item(pool, item_id, completed_at)
            .await
            .map_err(|e| {
                CompleteWaitingForError::Unexpected(anyhow::anyhow!(
                    "Failed to complete waiting-for item: {e}"
                ))
            })?;
    }

    tracing::info!("Waiting-for item completed");
    Ok(())
}

